import React, { useEffect, useState } from "react";
import "../index.css";

const OrdersPage = () => {
  const [orders, setOrders] = useState([]);
  const [userId, setUserId] = useState(""); // from Clerk or your auth system

  useEffect(() => {
    // ✅ Get userId from your auth (e.g., Clerk)
    const loggedInUser = JSON.parse(localStorage.getItem("user")); // or Clerk useUser()
    if (loggedInUser) setUserId(loggedInUser.id);

    if (loggedInUser) {
      fetch(`http://localhost:5002/api/orders/${loggedInUser.id}`)
        .then((res) => res.json())
        .then((data) => {
          if (data.success) setOrders(data.orders);
        })
        .catch((err) => console.error("Error fetching orders:", err));
    }
  }, []);

  // ✅ Cancel order (update DB)
  const handleCancel = async (orderId) => {
    const reason = prompt("Please enter the reason for cancelling this order:");
    if (!reason || reason.trim() === "") {
      alert("Cancellation reason is required!");
      return;
    }

    try {
      const res = await fetch(`http://localhost:5002/api/orders/cancel/${orderId}`, {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ reason }),
      });
      const data = await res.json();
      if (data.success) {
        alert("✅ Order cancelled successfully!");
        setOrders((prev) =>
          prev.map((order) =>
            order._id === orderId ? { ...order, status: "Cancelled", cancelReason: reason, cancelDate: new Date().toLocaleString() } : order
          )
        );
      } else {
        alert("Failed to cancel order!");
      }
    } catch (err) {
      console.error("Cancel error:", err);
    }
  };

  return (
    <div className="orders-page">
      <h2 className="orders-title">Your Orders</h2>

      {orders.length === 0 ? (
        <p className="no-orders">No orders found.</p>
      ) : (
        <div className="orders-list">
          {orders.map((order) => (
            <div key={order._id} className="order-card">
              <div className="order-header">
                <span>Order #{order._id.slice(-6).toUpperCase()}</span>
                <span
                  className={`order-status ${
                    order.status === "Cancelled" ? "cancelled" : "placed"
                  }`}
                >
                  {order.status}
                </span>
              </div>

              <p className="order-date">📅 {new Date(order.date).toLocaleString()}</p>

              <div className="order-items">
                {order.items.map((item, index) => (
                  <div key={index} className="order-item">
                    <img
                      src={item.image || "https://via.placeholder.com/80"}
                      alt={item.name}
                      className="order-item-img"
                    />
                    <div className="order-item-info">
                      <h4>{item.name}</h4>
                      <p>₹{item.price} × {item.quantity}</p>
                    </div>
                  </div>
                ))}
              </div>

              <div className="order-summary">
                <p><strong>Total:</strong> ₹{order.totalAmount}</p>
              </div>

              {order.status === "Cancelled" ? (
                <div className="cancel-info">
                  <p><strong>Cancelled On:</strong> {new Date(order.cancelDate).toLocaleString()}</p>
                  <p><strong>Reason:</strong> {order.cancelReason}</p>
                </div>
              ) : (
                <button className="cancel-btn" onClick={() => handleCancel(order._id)}>
                  Cancel Order
                </button>
              )}
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default OrdersPage;
